#!/usr/bin/env python3
"""Utility-greedy + BFS exploration planner for cogniplan_env."""
import os, sys, json, argparse, math, random
from collections import deque
import numpy as np
from cogniplan_env import ExplorationEnv

CELL_SIZE = 0.4
SUCCESS_THRESHOLD = 0.9999
MAX_STEPS = 128

def euclidean(a, b):
    return math.hypot(a[0]-b[0], a[1]-b[1])

def round_key(coord, decimals=3):
    return (round(coord[0], decimals), round(coord[1], decimals))

class UtilityGreedyPlanner:
    def __init__(self, eps=0.0):
        self.eps = eps
        self.nodes_coords = []
        self.coord_to_idx = {}
        self.adj = []
        self.n_nodes = 0

    def build_graph(self, nodes):
        self.n_nodes = len(nodes)
        self.nodes_coords = []
        self.coord_to_idx.clear()
        for i, nd in enumerate(nodes):
            x = float(nd['coords'][0])
            y = float(nd['coords'][1])
            rc = round_key((x, y))
            self.nodes_coords.append(rc)
            self.coord_to_idx[rc] = i
        self.adj = [[] for _ in range(self.n_nodes)]
        for i, nd in enumerate(nodes):
            for nb in nd.get('neighbors', []):
                key = round_key((float(nb[0]), float(nb[1])))
                j = self.coord_to_idx.get(key, -1)
                if j >= 0 and j != i:
                    if j not in self.adj[i]:
                        self.adj[i].append(j)
                    if i not in self.adj[j]:
                        self.adj[j].append(i)

    def get_closest_node_idx(self, pos):
        best_idx = 0
        best_d = float('inf')
        for i, coord in enumerate(self.nodes_coords):
            d = euclidean(pos, coord)
            if d < best_d:
                best_d = d
                best_idx = i
        return best_idx

    def bfs_path(self, start_idx, goal_idx):
        parent = [-1] * self.n_nodes
        seen = [False] * self.n_nodes
        q = deque([start_idx])
        seen[start_idx] = True
        while q:
            u = q.popleft()
            if u == goal_idx:
                break
            for v in self.adj[u]:
                if not seen[v]:
                    seen[v] = True
                    parent[v] = u
                    q.append(v)
        path = []
        if not seen[goal_idx]:
            return []
        curr = goal_idx
        while curr != start_idx:
            path.append(curr)
            curr = parent[curr]
        path.reverse()
        return path

    def select_action(self, obs, curr_idx, tabu):
        nodes = obs["nodes"]
        neighbors = obs["neighbors"]
        candidates = []
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx == -1:
                continue
            if nb_idx in tabu:
                continue
            utility = nodes[nb_idx]['utility']
            candidates.append((utility, nb_idx, nb_coords))
        # greedy local
        if candidates:
            max_util = max(c[0] for c in candidates)
            if max_util > 0:
                if random.random() < self.eps:
                    idx = random.randrange(len(candidates))
                    return candidates[idx][2], candidates[idx][1]
                best_utils = [c for c in candidates if c[0] == max_util]
                pos = obs["robot_pos"]
                best_utils.sort(key=lambda c: euclidean(pos, (nodes[c[1]]['coords'][0], nodes[c[1]]['coords'][1])))
                return best_utils[0][2], best_utils[0][1]
        # global BFS to max utility node
        global_best_idx = -1
        global_best_util = -1
        for i, nd in enumerate(nodes):
            if i in tabu:
                continue
            u = nd['utility']
            if u > global_best_util:
                global_best_util = u
                global_best_idx = i
        if global_best_util > 0:
            path = self.bfs_path(curr_idx, global_best_idx)
            if len(path) > 0:
                next_idx = path[0]
                target_coords = (nodes[next_idx]['coords'][0], nodes[next_idx]['coords'][1])
                return target_coords, next_idx
        # fallback: random neighbor not in tabu
        return self.random_neighbor(obs, tabu)

    def random_neighbor(self, obs, tabu):
        neighbors = obs["neighbors"]
        if not neighbors:
            return None, None
        nb_keys = []
        for nb_coords in neighbors:
            nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
            nb_idx = self.coord_to_idx.get(nb_key, -1)
            if nb_idx != -1 and nb_idx not in tabu:
                nb_keys.append((nb_coords, nb_idx))
        if nb_keys:
            choice = random.choice(nb_keys)
            return choice[0], choice[1]
        nb_coords = neighbors[0]
        nb_key = round_key((float(nb_coords[0]), float(nb_coords[1])))
        nb_idx = self.coord_to_idx.get(nb_key, -1)
        return nb_coords, nb_idx


def run_episode(env, planner):
    obs = env.reset()
    planner.build_graph(obs['nodes'])
    start_pos = obs['robot_pos']
    start_idx = planner.get_closest_node_idx(start_pos)
    curr_idx = start_idx
    tabu = deque(maxlen=3)
    step = 0
    while step < MAX_STEPS:
        if obs.get("explored_rate", 0) >= SUCCESS_THRESHOLD:
            break
        target_coords, next_idx = planner.select_action(obs, curr_idx, tabu)
        if target_coords is None:
            break
        obs_next, info = env.step(target_coords)
        curr_idx = planner.get_closest_node_idx(obs_next["robot_pos"])
        if next_idx != -1:
            tabu.append(curr_idx)
        obs = obs_next
        step += 1
        if info.get("done", False):
            break
    metrics = env.get_metrics()
    success = metrics.get("success", False)
    explored = metrics.get("explored_rate", 0.0)
    dist = metrics.get("travel_distance", 0.0)
    return {
        "success": 1 if success else 0,
        "explored_rate": explored,
        "travel_distance": dist,
        "n_steps": step
    }


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()
    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    with open(eval_config_path, "r") as f:
        config = json.load(f)
    maps_dir = os.path.join(args.data_path, "maps_eval")
    planner = UtilityGreedyPlanner(eps=0.0)
    per_episode = []
    for env_type in config.get("env_types", ["room", "tunnel", "outdoor"]):
        type_dir = os.path.join(maps_dir, env_type)
        if not os.path.isdir(type_dir):
            continue
        for fname in sorted(os.listdir(type_dir)):
            if not fname.endswith(".png"):
                continue
            map_path = os.path.join(type_dir, fname)
            env = ExplorationEnv(map_path=map_path)
            result = run_episode(env, planner)
            result["map_path"] = f"{env_type}/{fname}"
            result["env_type"] = env_type
            per_episode.append(result)
            env.__del__()  # clean up
    total_episodes = len(per_episode)
    if total_episodes == 0:
        output = {
            "explored_rate": 0.0,
            "travel_distance": 0.0,
            "success_rate": 0.0,
            "per_episode": [],
            "per_type": {
                "room": {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0},
                "tunnel": {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0},
                "outdoor": {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}
            },
            "total_episodes": 0
        }
        with open(args.output, "w") as f:
            json.dump(output, f, indent=2)
        return
    success_count = sum(e["success"] for e in per_episode)
    explored_rates = [e["explored_rate"] for e in per_episode]
    success_distance = [e["travel_distance"] for e in per_episode if e["success"]]
    overall = {
        "explored_rate": float(np.mean(explored_rates)),
        "travel_distance": float(np.mean(success_distance)) if success_distance else 0.0,
        "success_rate": success_count / total_episodes
    }
    per_type = {}
    for env_type in ["room", "tunnel", "outdoor"]:
        eps_type = [e for e in per_episode if e["env_type"] == env_type]
        if eps_type:
            sc = sum(e["success"] for e in eps_type)
            per_type[env_type] = {
                "explored_rate": float(np.mean([e["explored_rate"] for e in eps_type])),
                "travel_distance": float(np.mean([e["travel_distance"] for e in eps_type if e["success"]])) if any(e["success"] for e in eps_type) else 0.0,
                "success_rate": sc / len(eps_type)
            }
        else:
            per_type[env_type] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}
    output = {
        "explored_rate": overall["explored_rate"],
        "travel_distance": overall["travel_distance"],
        "success_rate": overall["success_rate"],
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total_episodes
    }
    with open(args.output, "w") as f:
        json.dump(output, f, indent=2)


if __name__ == "__main__":
    main()
